def sortedArrayToBST(nums):
    def build(left, right):
        if left > right:
            return None
        mid = (left + right) // 2
        root = TreeNode(nums[mid])
        root.left = build(left, mid - 1)
        root.right = build(mid + 1, right)
        return root
    return build(0, len(nums) - 1)

def pacificAtlantic(heights):
    if not heights:
        return []
    m, n = len(heights), len(heights[0])
    pacific = [[False]*n for _ in range(m)]
    atlantic = [[False]*n for _ in range(m)]
    def dfs(i, j, visited, prev_height):
        if i<0 or i>=m or j<0 or j>=n or visited[i][j] or heights[i][j] < prev_height:
            return
        visited[i][j] = True
        for di, dj in [(1,0),(-1,0),(0,1),(0,-1)]:
            dfs(i+di, j+dj, visited, heights[i][j])
    for i in range(m):
        dfs(i, 0, pacific, heights[i][0])
        dfs(i, n-1, atlantic, heights[i][n-1])
    for j in range(n):
        dfs(0, j, pacific, heights[0][j])
        dfs(m-1, j, atlantic, heights[m-1][j])
    result = []
    for i in range(m):
        for j in range(n):
            if pacific[i][j] and atlantic[i][j]:
                result.append([i, j])
    return result

def uniquePaths(m, n):
    dp = [1] * n
    for i in range(1, m):
        for j in range(1, n):
            dp[j] += dp[j-1]
    return dp[-1]

def setZeroes(matrix):
    m, n = len(matrix), len(matrix[0])
    first_row_zero = any(matrix[0][j] == 0 for j in range(n))
    first_col_zero = any(matrix[i][0] == 0 for i in range(m))
    for i in range(1, m):
        for j in range(1, n):
            if matrix[i][j] == 0:
                matrix[i][0] = matrix[0][j] = 0
    for i in range(1, m):
        for j in range(1, n):
            if matrix[i][0] == 0 or matrix[0][j] == 0:
                matrix[i][j] = 0
    if first_row_zero:
        for j in range(n):
            matrix[0][j] = 0
    if first_col_zero:
        for i in range(m):
            matrix[i][0] = 0

def ladderLength(beginWord, endWord, wordList):
    from collections import defaultdict, deque
    if endWord not in wordList:
        return 0
    wordList.append(beginWord)
    pattern_dict = defaultdict(list)
    for word in wordList:
        for i in range(len(word)):
            pattern = word[:i] + '*' + word[i+1:]
            pattern_dict[pattern].append(word)
    visited = set([beginWord])
    queue = deque([(beginWord, 1)])
    while queue:
        word, level = queue.popleft()
        for i in range(len(word)):
            pattern = word[:i] + '*' + word[i+1:]
            for neighbor in pattern_dict[pattern]:
                if neighbor == endWord:
                    return level + 1
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append((neighbor, level + 1))
    return 0

def evalRPN(tokens):
    stack = []
    for token in tokens:
        if token in {'+', '-', '*', '/'}:
            b = stack.pop()
            a = stack.pop()
            if token == '+':
                stack.append(a + b)
            elif token == '-':
                stack.append(a - b)
            elif token == '*':
                stack.append(a * b)
            else:
                stack.append(int(a / b))
        else:
            stack.append(int(token))
    return stack[0]

def calculate(s):
    stack = []
    num = 0
    sign = '+'
    for i, char in enumerate(s):
        if char.isdigit():
            num = num * 10 + int(char)
        if char in '+-*/' or i == len(s) - 1:
            if sign == '+':
                stack.append(num)
            elif sign == '-':
                stack.append(-num)
            elif sign == '*':
                stack.append(stack.pop() * num)
            elif sign == '/':
                stack.append(int(stack.pop() / num))
            sign = char
            num = 0
    return sum(stack)

def findDuplicate(nums):
    slow = fast = nums[0]
    while True:
        slow = nums[slow]
        fast = nums[nums[fast]]
        if slow == fast:
            break
    slow = nums[0]
    while slow != fast:
        slow = nums[slow]
        fast = nums[fast]
    return slow

def subsets(nums):
    result = []
    def backtrack(start, current):
        result.append(current[:])
        for i in range(start, len(nums)):
            current.append(nums[i])
            backtrack(i + 1, current)
            current.pop()
    backtrack(0, [])
    return result

def rotate(matrix):
    n = len(matrix)
    for i in range(n):
        for j in range(i, n):
            matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]
    for i in range(n):
        matrix[i].reverse()

def longestCommonSubsequence(text1, text2):
    m, n = len(text1), len(text2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if text1[i-1] == text2[j-1]:
                dp[i][j] = dp[i-1][j-1] + 1
            else:
                dp[i][j] = max(dp[i-1][j], dp[i][j-1])
    return dp[m][n]

def validTree(n, edges):
    if len(edges) != n - 1:
        return False
    parent = list(range(n))
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    def union(x, y):
        parent[find(x)] = find(y)
    for u, v in edges:
        if find(u) == find(v):
            return False
        union(u, v)
    return True

def invertTree(root):
    if not root:
        return None
    root.left, root.right = invertTree(root.right), invertTree(root.left)
    return root

def isSameTree(p, q):
    if not p and not q:
        return True
    if not p or not q:
        return False
    return p.val == q.val and isSameTree(p.left, q.left) and isSameTree(p.right, q.right)

def isBalanced(root):
    def check(node):
        if not node:
            return 0
        left = check(node.left)
        if left == -1:
            return -1
        right = check(node.right)
        if right == -1:
            return -1
        if abs(left - right) > 1:
            return -1
        return 1 + max(left, right)
    return check(root) != -1

def buildTree(preorder, inorder):
    in_map = {val: i for i, val in enumerate(inorder)}
    pre_idx = 0
    def build(left, right):
        nonlocal pre_idx
        if left > right:
            return None
        val = preorder[pre_idx]
        pre_idx += 1
        root = TreeNode(val)
        root.left = build(left, in_map[val] - 1)
        root.right = build(in_map[val] + 1, right)
        return root
    return build(0, len(inorder) - 1)

def leastInterval(tasks, n):
    from collections import Counter
    freq = list(Counter(tasks).values())
    max_freq = max(freq)
    max_count = freq.count(max_freq)
    return max(len(tasks), (max_freq - 1) * (n + 1) + max_count)

class Twitter:
    def __init__(self):
        self.tweets = collections.defaultdict(list)
        self.followees = collections.defaultdict(set)
        self.time = 0

    def postTweet(self, userId, tweetId):
        self.tweets[userId].append((self.time, tweetId))
        self.time += 1

    def getNewsFeed(self, userId):
        import heapq
        feed = []
        followees = self.followees[userId] | {userId}
        for followeeId in followees:
            for t in self.tweets[followeeId][-10:]:
                heapq.heappush(feed, t)
                if len(feed) > 10:
                    heapq.heappop(feed)
        result = []
        while feed:
            result.append(heapq.heappop(feed)[1])
        return result[::-1]

    def follow(self, followerId, followeeId):
        self.followees[followerId].add(followeeId)

    def unfollow(self, followerId, followeeId):
        self.followees[followerId].discard(followeeId)

def connect(root):
    if not root:
        return None
    leftmost = root
    while leftmost.left:
        head = leftmost
        while head:
            head.left.next = head.right
            if head.next:
                head.right.next = head.next.left
            head = head.next
        leftmost = leftmost.left
    return root

def wallsAndGates(rooms):
    from collections import deque
    if not rooms:
        return
    m, n = len(rooms), len(rooms[0])
    queue = deque()
    for i in range(m):
        for j in range(n):
            if rooms[i][j] == 0:
                queue.append((i, j))
    INF = 2**31 - 1
    directions = [(1,0), (-1,0), (0,1), (0,-1)]
    while queue:
        i, j = queue.popleft()
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and rooms[ni][nj] == INF:
                rooms[ni][nj] = rooms[i][j] + 1
                queue.append((ni, nj))

def flatten(root):
    curr = root
    while curr:
        if curr.left:
            predecessor = curr.left
            while predecessor.right:
                predecessor = predecessor.right
            predecessor.right = curr.right
            curr.right = curr.left
            curr.left = None
        curr = curr.right

def updateMatrix(mat):
    from collections import deque
    m, n = len(mat), len(mat[0])
    queue = deque()
    for i in range(m):
        for j in range(n):
            if mat[i][j] == 0:
                queue.append((i, j))
            else:
                mat[i][j] = float('inf')
    directions = [(1,0), (-1,0), (0,1), (0,-1)]
    while queue:
        i, j = queue.popleft()
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and mat[ni][nj] > mat[i][j] + 1:
                mat[ni][nj] = mat[i][j] + 1
                queue.append((ni, nj))
    return mat

def partitionLabels(s):
    last = {c: i for i, c in enumerate(s)}
    result = []
    start = end = 0
    for i, c in enumerate(s):
        end = max(end, last[c])
        if i == end:
            result.append(end - start + 1)
            start = i + 1
    return result

def asteroidCollision(asteroids):
    stack = []
    for asteroid in asteroids:
        while stack and asteroid < 0 < stack[-1]:
            if stack[-1] < -asteroid:
                stack.pop()
                continue
            elif stack[-1] == -asteroid:
                stack.pop()
                break
            else:
                break
        else:
            stack.append(asteroid)
    return stack

def minSubArrayLen(target, nums):
    left = total = 0
    min_len = float('inf')
    for right in range(len(nums)):
        total += nums[right]
        while total >= target:
            min_len = min(min_len, right - left + 1)
            total -= nums[left]
            left += 1
    return min_len if min_len != float('inf') else 0

def canCompleteCircuit(gas, cost):
    total_tank = curr_tank = start = 0
    for i in range(len(gas)):
        total_tank += gas[i] - cost[i]
        curr_tank += gas[i] - cost[i]
        if curr_tank < 0:
            start = i + 1
            curr_tank = 0
    return start if total_tank >= 0 else -1

def rob(nums):
    def rob_linear(arr):
        prev1 = prev2 = 0
        for num in arr:
            temp = max(prev1, prev2 + num)
            prev2 = prev1
            prev1 = temp
        return prev1
    if len(nums) == 1:
        return nums[0]
    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

def maximalRectangle(matrix):
    if not matrix:
        return 0
    n = len(matrix[0])
    heights = [0] * (n + 1)
    max_area = 0
    for row in matrix:
        for i in range(n):
            heights[i] = heights[i] + 1 if row[i] == '1' else 0
        stack = []
        for i in range(n + 1):
            while stack and heights[i] < heights[stack[-1]]:
                h = heights[stack.pop()]
                w = i if not stack else i - stack[-1] - 1
                max_area = max(max_area, h * w)
            stack.append(i)
    return max_area

def numDecodings(s):
    MOD = 10**9 + 7
    dp = [0] * (len(s) + 1)
    dp[0] = 1
    dp[1] = 9 if s[0] == '*' else (1 if s[0] != '0' else 0)
    for i in range(2, len(s) + 1):
        if s[i-1] == '*':
            dp[i] = 9 * dp[i-1]
            if s[i-2] == '1':
                dp[i] += 9 * dp[i-2]
            elif s[i-2] == '2':
                dp[i] += 6 * dp[i-2]
            elif s[i-2] == '*':
                dp[i] += 15 * dp[i-2]
        else:
            dp[i] = dp[i-1] if s[i-1] != '0' else 0
            if s[i-2] == '1' or (s[i-2] == '2' and s[i-1] <= '6'):
                dp[i] += dp[i-2]
            elif s[i-2] == '*':
                dp[i] += dp[i-2] * (2 if s[i-1] <= '6' else 1)
        dp[i] %= MOD
    return dp[-1]

def kthSmallest(matrix, k):
    import bisect
    n = len(matrix)
    lo, hi = matrix[0][0], matrix[-1][-1]
    while lo < hi:
        mid = (lo + hi) // 2
        count = sum(bisect.bisect_right(row, mid) for row in matrix)
        if count < k:
            lo = mid + 1
        else:
            hi = mid
    return lo

def dailyTemperatures(temperatures):
    n = len(temperatures)
    result = [0] * n
    stack = []
    for i, temp in enumerate(temperatures):
        while stack and temperatures[stack[-1]] < temp:
            prev_day = stack.pop()
            result[prev_day] = i - prev_day
        stack.append(i)
    return result

def findMin(nums):
    left, right = 0, len(nums) - 1
    while left < right:
        mid = (left + right) // 2
        if nums[mid] > nums[right]:
            left = mid + 1
        else:
            right = mid
    return nums[left]

def maxPathSum(root):
    max_sum = float('-inf')
    def max_gain(node):
        nonlocal max_sum
        if not node:
            return 0
        left_gain = max(max_gain(node.left), 0)
        right_gain = max(max_gain(node.right), 0)
        max_sum = max(max_sum, node.val + left_gain + right_gain)
        return node.val + max(left_gain, right_gain)
    max_gain(root)
    return max_sum

def findWords(board, words):
    trie = {}
    for word in words:
        node = trie
        for char in word:
            node = node.setdefault(char, {})
        node['#'] = word
    rows, cols = len(board), len(board[0])
    result = set()
    def dfs(i, j, node):
        if '#' in node:
            result.add(node['#'])
        if i<0 or i>=rows or j<0 or j>=cols or board[i][j] not in node:
            return
        char = board[i][j]
        board[i][j] = '#'
        dfs(i+1, j, node[char])
        dfs(i-1, j, node[char])
        dfs(i, j+1, node[char])
        dfs(i, j-1, node[char])
        board[i][j] = char
    for i in range(rows):
        for j in range(cols):
            dfs(i, j, trie)
    return list(result)

def numberToWords(num):
    if num == 0:
        return "Zero"
    ones = ['','One','Two','Three','Four','Five','Six','Seven','Eight','Nine','Ten','Eleven','Twelve','Thirteen','Fourteen','Fifteen','Sixteen','Seventeen','Eighteen','Nineteen']
    tens = ['','','Twenty','Thirty','Forty','Fifty','Sixty','Seventy','Eighty','Ninety']
    thousands = ['','Thousand','Million','Billion']
    def helper(n):
        if n == 0:
            return ''
        elif n < 20:
            return ones[n] + ' '
        elif n < 100:
            return tens[n//10] + ' ' + helper(n%10)
        else:
            return ones[n//100] + ' Hundred ' + helper(n%100)
    result = ''
    for i, unit in enumerate(thousands):
        if num % 1000 != 0:
            result = helper(num % 1000) + unit + ' ' + result
        num //= 1000
    return result.strip()

def findAllConcatenatedWords(words):
    word_set = set(words)
    def canConcat(word):
        dp = [False] * (len(word) + 1)
        dp[0] = True
        for i in range(1, len(word) + 1):
            for j in range(1 if i != len(word) else 1, i):
                if dp[j] and word[j:i] in word_set:
                    dp[i] = True
                    break
        return dp[-1]
    result = []
    for word in sorted(words, key=len):
        if word and canConcat(word):
            result.append(word)
    return result

def alienOrder(words):
    from collections import defaultdict, deque
    graph = defaultdict(set)
    indegree = {c: 0 for word in words for c in word}
    for i in range(len(words)-1):
        w1, w2 = words[i], words[i+1]
        min_len = min(len(w1), len(w2))
        if w1[:min_len] == w2[:min_len] and len(w1) > len(w2):
            return ""
        for j in range(min_len):
            if w1[j] != w2[j]:
                if w2[j] not in graph[w1[j]]:
                    graph[w1[j]].add(w2[j])
                    indegree[w2[j]] += 1
                break
    queue = deque([c for c in indegree if indegree[c] == 0])
    result = []
    while queue:
        c = queue.popleft()
        result.append(c)
        for neighbor in graph[c]:
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)
    return ''.join(result) if len(result) == len(indegree) else ""

def change(amount, coins):
    dp = [0] * (amount + 1)
    dp[0] = 1
    for coin in coins:
        for x in range(coin, amount + 1):
            dp[x] += dp[x - coin]
    return dp[amount]

def exclusiveTime(n, logs):
    result = [0] * n
    stack = []
    prev_time = 0
    for log in logs:
        fid, action, time = log.split(':')
        fid, time = int(fid), int(time)
        if action == 'start':
            if stack:
                result[stack[-1]] += time - prev_time
            stack.append(fid)
            prev_time = time
        else:
            result[stack.pop()] += time - prev_time + 1
            prev_time = time + 1
    return result

def countNodes(root):
    if not root:
        return 0
    left_depth = right_depth = 0
    node = root
    while node:
        left_depth += 1
        node = node.left
    node = root
    while node:
        right_depth += 1
        node = node.right
    if left_depth == right_depth:
        return 2**left_depth - 1
    return 1 + countNodes(root.left) + countNodes(root.right)

def removeInvalidParentheses(s):
    from collections import deque
    def isValid(s):
        count = 0
        for c in s:
            if c == '(':
                count += 1
            elif c == ')':
                count -= 1
            if count < 0:
                return False
        return count == 0
    queue = deque([s])
    visited = set([s])
    found = False
    result = []
    while queue and not found:
        level_size = len(queue)
        for _ in range(level_size):
            curr = queue.popleft()
            if isValid(curr):
                result.append(curr)
                found = True
            if found:
                continue
            for i in range(len(curr)):
                if curr[i] not in '()':
                    continue
                next_str = curr[:i] + curr[i+1:]
                if next_str not in visited:
                    visited.add(next_str)
                    queue.append(next_str)
    return result

def isInterleave(s1, s2, s3):
    if len(s1) + len(s2) != len(s3):
        return False
    dp = [False] * (len(s2) + 1)
    for i in range(len(s1) + 1):
        for j in range(len(s2) + 1):
            if i == 0 and j == 0:
                dp[j] = True
            elif i == 0:
                dp[j] = dp[j-1] and s2[j-1] == s3[j-1]
            elif j == 0:
                dp[j] = dp[j] and s1[i-1] == s3[i-1]
            else:
                dp[j] = (dp[j] and s1[i-1] == s3[i+j-1]) or (dp[j-1] and s2[j-1] == s3[i+j-1])
    return dp[-1]

def addOperators(num, target):
    result = []
    def backtrack(index, path, value, prev):
        if index == len(num):
            if value == target:
                result.append(path)
            return
        for i in range(index, len(num)):
            if i != index and num[index] == '0':
                break
            curr = int(num[index:i+1])
            if index == 0:
                backtrack(i+1, path + str(curr), curr, curr)
            else:
                backtrack(i+1, path + '+' + str(curr), value + curr, curr)
                backtrack(i+1, path + '-' + str(curr), value - curr, -curr)
                backtrack(i+1, path + '*' + str(curr), value - prev + prev * curr, prev * curr)
    backtrack(0, '', 0, 0)
    return result

class LFUCache:
    def __init__(self, capacity):
        self.capacity = capacity
        self.min_freq = 0
        self.key_val = {}
        self.key_freq = {}
        self.freq_keys = collections.defaultdict(OrderedDict)

    def get(self, key):
        if key not in self.key_val:
            return -1
        freq = self.key_freq[key]
        del self.freq_keys[freq][key]
        if not self.freq_keys[freq] and self.min_freq == freq:
            self.min_freq += 1
        self.key_freq[key] = freq + 1
        self.freq_keys[freq + 1][key] = None
        return self.key_val[key]

    def put(self, key, value):
        if self.capacity == 0:
            return
        if key in self.key_val:
            self.key_val[key] = value
            self.get(key)
            return
        if len(self.key_val) >= self.capacity:
            evict_key, _ = self.freq_keys[self.min_freq].popitem(last=False)
            del self.key_val[evict_key]
            del self.key_freq[evict_key]
        self.key_val[key] = value
        self.key_freq[key] = 1
        self.freq_keys[1][key] = None
        self.min_freq = 1

def addBoldTag(s, dict):
    n = len(s)
    bold = [False] * n
    for word in dict:
        start = s.find(word)
        while start != -1:
            for i in range(start, start + len(word)):
                bold[i] = True
            start = s.find(word, start + 1)
    result = []
    i = 0
    while i < n:
        if bold[i]:
            result.append('<b>')
            while i < n and bold[i]:
                result.append(s[i])
                i += 1
            result.append('</b>')
        else:
            result.append(s[i])
            i += 1
    return ''.join(result)

def numBusesToDestination(routes, source, target):
    if source == target:
        return 0
    from collections import defaultdict, deque
    stop_to_routes = defaultdict(set)
    for i, route in enumerate(routes):
        for stop in route:
            stop_to_routes[stop].add(i)
    queue = deque([(source, 0)])
    visited_stops = {source}
    visited_routes = set()
    while queue:
        stop, buses = queue.popleft()
        if stop == target:
            return buses
        for route_id in stop_to_routes[stop]:
            if route_id not in visited_routes:
                visited_routes.add(route_id)
                for next_stop in routes[route_id]:
                    if next_stop not in visited_stops:
                        visited_stops.add(next_stop)
                        queue.append((next_stop, buses + 1))
    return -1

def numSubarrayProductLessThanK(nums, k):
    if k <= 1:
        return 0
    prod = 1
    count = left = 0
    for right, num in enumerate(nums):
        prod *= num
        while prod >= k:
            prod /= nums[left]
            left += 1
        count += right - left + 1
    return count

class TimeMap:
    def __init__(self):
        from collections import defaultdict
        self.store = defaultdict(list)

    def set(self, key, value, timestamp):
        self.store[key].append((timestamp, value))

    def get(self, key, timestamp):
        import bisect
        if key not in self.store:
            return ""
        arr = self.store[key]
        i = bisect.bisect_right(arr, (timestamp, chr(127)))
        return arr[i-1][1] if i > 0 else ""

def checkInclusion(s1, s2):
    from collections import Counter
    len1, len2 = len(s1), len(s2)
    if len1 > len2:
        return False
    s1_count = Counter(s1)
    window = Counter(s2[:len1])
    if s1_count == window:
        return True
    for i in range(len1, len2):
        window[s2[i]] += 1
        window[s2[i-len1]] -= 1
        if window[s2[i-len1]] == 0:
            del window[s2[i-len1]]
        if s1_count == window:
            return True
    return False

def findClosestElements(arr, k, x):
    import bisect
    right = bisect.bisect_left(arr, x)
    left = right - 1
    while k > 0:
        if left < 0:
            right += 1
        elif right >= len(arr):
            left -= 1
        elif abs(arr[left] - x) <= abs(arr[right] - x):
            left -= 1
        else:
            right += 1
        k -= 1
    return arr[left+1:right]

def openLock(deadends, target):
    from collections import deque
    dead = set(deadends)
    if '0000' in dead:
        return -1
    queue = deque([('0000', 0)])
    visited = {'0000'}
    while queue:
        state, turns = queue.popleft()
        if state == target:
            return turns
        for i in range(4):
            for d in [-1, 1]:
                new_digit = (int(state[i]) + d) % 10
                new_state = state[:i] + str(new_digit) + state[i+1:]
                if new_state not in dead and new_state not in visited:
                    visited.add(new_state)
                    queue.append((new_state, turns + 1))
    return -1

def splitArray(nums, m):
    def feasible(threshold):
        count = total = 1
        for num in nums:
            total += num
            if total > threshold:
                total = num
                count += 1
                if count > m:
                    return False
        return True
    left, right = max(nums), sum(nums)
    while left < right:
        mid = (left + right) // 2
        if feasible(mid):
            right = mid
        else:
            left = mid + 1
    return left

def eventualSafeNodes(graph):
    n = len(graph)
    state = [0] * n
    def is_safe(node):
        if state[node] != 0:
            return state[node] == 2
        state[node] = 1
        for nei in graph[node]:
            if state[nei] == 1 or not is_safe(nei):
                return False
        state[node] = 2
        return True
    return [i for i in range(n) if is_safe(i)]

class MyCalendar:
    def __init__(self):
        import bisect
        self.start_times = []
        self.end_times = []

    def book(self, start, end):
        import bisect
        i = bisect.bisect_right(self.start_times, start)
        if i > 0 and self.end_times[i-1] > start:
            return False
        if i < len(self.start_times) and self.start_times[i] < end:
            return False
        self.start_times.insert(i, start)
        self.end_times.insert(i, end)
        return True

def longestOnes(nums, k):
    left = zero_count = max_len = 0
    for right in range(len(nums)):
        if nums[right] == 0:
            zero_count += 1
        while zero_count > k:
            if nums[left] == 0:
                zero_count -= 1
            left += 1
        max_len = max(max_len, right - left + 1)
    return max_len

def carFleet(target, position, speed):
    cars = sorted(zip(position, speed), reverse=True)
    fleets = 0
    last_time = -1.0
    for pos, spd in cars:
        time = (target - pos) / spd
        if time > last_time:
            fleets += 1
            last_time = time
    return fleets

class Solution:
