        target = random.randint(1, self.total)
        return bisect.bisect_left(self.prefix, target)

class NumMatrix:
    def __init__(self, matrix):
        if not matrix:
            return
        m, n = len(matrix), len(matrix[0])
        self.prefix = [[0] * (n+1) for _ in range(m+1)]
        for i in range(m):
            for j in range(n):
                self.prefix[i+1][j+1] = matrix[i][j] + self.prefix[i][j+1] + self.prefix[i+1][j] - self.prefix[i][j]

    def sumRegion(self, row1, col1, row2, col2):
        return (self.prefix[row2+1][col2+1] - self.prefix[row1][col2+1] - self.prefix[row2+1][col1] + self.prefix[row1][col1])

def largestNumber(nums):
    from functools import cmp_to_key
    nums = list(map(str, nums))
    def compare(x, y):
        if x + y > y + x:
            return -1
        elif x + y < y + x:
            return 1
        return 0
    nums.sort(key=cmp_to_key(compare))
    result = ''.join(nums)
    return '0' if result[0] == '0' else result

def nextPermutation(nums):
    i = len(nums) - 2
    while i >= 0 and nums[i] >= nums[i+1]:
        i -= 1
    if i >= 0:
        j = len(nums) - 1
        while j >= 0 and nums[j] <= nums[i]:
            j -= 1
        nums[i], nums[j] = nums[j], nums[i]
    left, right = i + 1, len(nums) - 1
    while left < right:
        nums[left], nums[right] = nums[right], nums[left]
        left += 1
        right -= 1

def mctFromLeafValues(arr):
    stack = [float('inf')]
    result = 0
    for val in arr:
        while stack[-1] <= val:
            mid = stack.pop()
            result += mid * min(stack[-1], val)
        stack.append(val)
    while len(stack) > 2:
        result += stack.pop() * stack[-1]
    return result

def shortestSubarray(nums, k):
    from collections import deque
    n = len(nums)
    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i+1] = prefix[i] + nums[i]
    dq = deque()
    result = n + 1
    for i in range(n + 1):
        while dq and prefix[i] - prefix[dq[0]] >= k:
            result = min(result, i - dq.popleft())
        while dq and prefix[i] <= prefix[dq[-1]]:
            dq.pop()
        dq.append(i)
    return result if result <= n else -1

def candy(ratings):
    n = len(ratings)
    candies = [1] * n
    for i in range(1, n):
        if ratings[i] > ratings[i-1]:
            candies[i] = candies[i-1] + 1
    for i in range(n-2, -1, -1):
        if ratings[i] > ratings[i+1]:
            candies[i] = max(candies[i], candies[i+1] + 1)
    return sum(candies)

def countComponents(n, edges):
    parent = list(range(n))
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    def union(x, y):
        parent[find(x)] = find(y)
    for u, v in edges:
        if find(u) != find(v):
            union(u, v)
            n -= 1
    return n

def isMatch(s, p):
    s_len, p_len = len(s), len(p)
    s_idx = p_idx = 0
    star_idx = s_tmp_idx = -1
    while s_idx < s_len:
        if p_idx < p_len and (p[p_idx] == '?' or p[p_idx] == s[s_idx]):
            s_idx += 1
            p_idx += 1
        elif p_idx < p_len and p[p_idx] == '*':
            star_idx = p_idx
            s_tmp_idx = s_idx
            p_idx += 1
        elif star_idx != -1:
            p_idx = star_idx + 1
            s_tmp_idx += 1
            s_idx = s_tmp_idx
        else:
            return False
    while p_idx < p_len and p[p_idx] == '*':
        p_idx += 1
    return p_idx == p_len

def minRemoveToMakeValid(s):
    s = list(s)
    stack = []
    for i, c in enumerate(s):
        if c == '(':
            stack.append(i)
        elif c == ')':
            if stack:
                stack.pop()
            else:
                s[i] = ''
    for i in stack:
        s[i] = ''
    return ''.join(s)

def jump(nums):
    jumps = curr_end = farthest = 0
    for i in range(len(nums) - 1):
        farthest = max(farthest, i + nums[i])
        if i == curr_end:
            jumps += 1
            curr_end = farthest
    return jumps

class RandomizedSet:
    def __init__(self):
        self.nums = []
        self.pos = {}
    def insert(self, val):
        if val in self.pos:
            return False
        self.pos[val] = len(self.nums)
        self.nums.append(val)
        return True
    def remove(self, val):
        if val not in self.pos:
            return False
        idx = self.pos[val]
        last = self.nums[-1]
        self.nums[idx] = last
        self.pos[last] = idx
        self.nums.pop()
        del self.pos[val]
        return True
    def getRandom(self):
        return random.choice(self.nums)

def getRow(rowIndex):
    row = [1]
    for i in range(1, rowIndex + 1):
        row.append(1)
        for j in range(i - 1, 0, -1):
            row[j] = row[j] + row[j-1]
    return row

def zigzagLevelOrder(root):
    if not root:
        return []
    from collections import deque
    result = []
    queue = deque([root])
    left_to_right = True
    while queue:
        level = []
        for _ in range(len(queue)):
            node = queue.popleft()
            level.append(node.val)
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        if not left_to_right:
            level.reverse()
        result.append(level)
        left_to_right = not left_to_right
    return result

def isValidSerialization(preorder):
    slots = 1
    for node in preorder.split(','):
        slots -= 1
        if slots < 0:
            return False
        if node != '#':
            slots += 2
    return slots == 0

def findPeakElement(nums):
    left, right = 0, len(nums) - 1
    while left < right:
        mid = (left + right) // 2
        if nums[mid] < nums[mid+1]:
            left = mid + 1
        else:
            right = mid
    return left

def boundaryOfBinaryTree(root):
    if not root:
        return []
    result = [root.val]
    def left_boundary(node):
        if not node or (not node.left and not node.right):
            return
        result.append(node.val)
        if node.left:
            left_boundary(node.left)
        else:
            left_boundary(node.right)
    def leaves(node):
        if not node:
            return
        if not node.left and not node.right:
            result.append(node.val)
            return
        leaves(node.left)
        leaves(node.right)
    def right_boundary(node):
        if not node or (not node.left and not node.right):
            return
        if node.right:
            right_boundary(node.right)
        else:
            right_boundary(node.left)
        result.append(node.val)
    left_boundary(root.left)
    leaves(root.left)
    leaves(root.right)
    right_boundary(root.right)
    return result

def depthSumInverse(nestedList):
    from collections import deque
    if not nestedList:
        return 0
    queue = deque(nestedList)
    unweighted = weighted = 0
    while queue:
        level_size = len(queue)
        level_sum = 0
        for _ in range(level_size):
            ni = queue.popleft()
            if ni.isInteger():
                level_sum += ni.getInteger()
            else:
                queue.extend(ni.getList())
        unweighted += level_sum
        weighted += unweighted
    return weighted

def longestValidParentheses(s):
    stack = [-1]
    max_len = 0
    for i, char in enumerate(s):
        if char == '(':
            stack.append(i)
        else:
            stack.pop()
            if not stack:
                stack.append(i)
            else:
                max_len = max(max_len, i - stack[-1])
    return max_len

def minAvailableDuration(slots1, slots2, duration):
    slots1.sort()
    slots2.sort()
    i = j = 0
    while i < len(slots1) and j < len(slots2):
        start = max(slots1[i][0], slots2[j][0])
        end = min(slots1[i][1], slots2[j][1])
        if end - start >= duration:
            return [start, start + duration]
        if slots1[i][1] < slots2[j][1]:
            i += 1
        else:
            j += 1
    return []

def frequencySort(s):
    from collections import Counter
    count = Counter(s)
    buckets = [[] for _ in range(len(s) + 1)]
    for char, freq in count.items():
        buckets[freq].append(char)
    result = []
    for freq in range(len(s), 0, -1):
        for char in buckets[freq]:
            result.append(char * freq)
    return ''.join(result)

def findPairs(nums, k):
    if k < 0:
        return 0
    from collections import Counter
    count = Counter(nums)
    result = 0
    for num in count:
        if k == 0:
            if count[num] > 1:
                result += 1
        else:
            if num + k in count:
                result += 1
    return result

def maximumMinimumPath(grid):
    import heapq
    m, n = len(grid), len(grid[0])
    heap = [(-grid[0][0], 0, 0)]
    visited = {(0, 0)}
    directions = [(0,1), (0,-1), (1,0), (-1,0)]
    while heap:
        val, i, j = heapq.heappop(heap)
        if i == m-1 and j == n-1:
            return -val
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if 0 <= ni < m and 0 <= nj < n and (ni, nj) not in visited:
                visited.add((ni, nj))
                heapq.heappush(heap, (-min(-val, grid[ni][nj]), ni, nj))

def maxSubArrayLen(nums, k):
    prefix_sum = 0
    max_len = 0
    sum_index = {0: -1}
    for i, num in enumerate(nums):
        prefix_sum += num
        if prefix_sum - k in sum_index:
            max_len = max(max_len, i - sum_index[prefix_sum - k])
        if prefix_sum not in sum_index:
            sum_index[prefix_sum] = i
    return max_len

class Codec:
    def encode(self, strs):
        return ''.join(f'{len(s)}#{s}' for s in strs)

    def decode(self, s):
        result = []
        i = 0
        while i < len(s):
            j = s.find('#', i)
            length = int(s[i:j])
            result.append(s[j+1:j+1+length])
            i = j + 1 + length
        return result

