class WordDistance:
    def __init__(self, wordsDict):
        self.indices = collections.defaultdict(list)
        for i, word in enumerate(wordsDict):
            self.indices[word].append(i)

    def shortest(self, word1, word2):
        idx1, idx2 = self.indices[word1], self.indices[word2]
        i = j = 0
        min_dist = float('inf')
        while i < len(idx1) and j < len(idx2):
            min_dist = min(min_dist, abs(idx1[i] - idx2[j]))
            if idx1[i] < idx2[j]:
                i += 1
            else:
                j += 1
        return min_dist

def maximumAverageSubtree(root):
    max_avg = 0
    def dfs(node):
        nonlocal max_avg
        if not node:
            return (0, 0)
        left_sum, left_cnt = dfs(node.left)
        right_sum, right_cnt = dfs(node.right)
        total = left_sum + right_sum + node.val
        count = left_cnt + right_cnt + 1
        max_avg = max(max_avg, total / count)
        return (total, count)
    dfs(root)
    return max_avg

def isBipartite(graph):
    from collections import deque
    n = len(graph)
    color = [0] * n
    for i in range(n):
        if color[i] == 0:
            color[i] = 1
            queue = deque([i])
            while queue:
                node = queue.popleft()
                for neighbor in graph[node]:
                    if color[neighbor] == 0:
                        color[neighbor] = -color[node]
                        queue.append(neighbor)
                    elif color[neighbor] == color[node]:
                        return False
    return True

def flipEquiv(root1, root2):
    if not root1 and not root2:
        return True
    if not root1 or not root2 or root1.val != root2.val:
        return False
    return (flipEquiv(root1.left, root2.left) and flipEquiv(root1.right, root2.right)) or (flipEquiv(root1.left, root2.right) and flipEquiv(root1.right, root2.left))

def numMatchingSubseq(s, words):
    from collections import defaultdict
    import bisect
    pos = defaultdict(list)
    for i, c in enumerate(s):
        pos[c].append(i)
    result = 0
    for word in words:
        prev = -1
        found = True
        for c in word:
            if c not in pos:
                found = False
                break
            idx = bisect.bisect_right(pos[c], prev)
            if idx == len(pos[c]):
                found = False
                break
            prev = pos[c][idx]
        if found:
            result += 1
    return result

class BSTPreorderIterator:
    def __init__(self, root):
        self.stack = [root] if root else []

    def next(self):
        node = self.stack.pop()
        if node.right:
            self.stack.append(node.right)
        if node.left:
            self.stack.append(node.left)
        return node.val

    def hasNext(self):
        return len(self.stack) > 0

def minimumSemesters(n, relations):
    from collections import defaultdict, deque
    graph = defaultdict(list)
    indegree = [0] * (n + 1)
    for prev, nxt in relations:
        graph[prev].append(nxt)
        indegree[nxt] += 1
    queue = deque([i for i in range(1, n+1) if indegree[i] == 0])
    semesters = 0
    studied = 0
    while queue:
        semesters += 1
        for _ in range(len(queue)):
            course = queue.popleft()
            studied += 1
            for neighbor in graph[course]:
                indegree[neighbor] -= 1
                if indegree[neighbor] == 0:
                    queue.append(neighbor)
    return semesters if studied == n else -1

def nextClosestTime(time):
    digits = {time[0], time[1], time[3], time[4]}
    minutes = int(time[:2]) * 60 + int(time[3:])
    for _ in range(1, 24*60):
        minutes = (minutes + 1) % (24*60)
        h = minutes // 60
        m = minutes % 60
        time_str = f'{h:02d}{m:02d}'
        if all(d in digits for d in time_str):
            return f'{h:02d}:{m:02d}'

def numDistinctIslands(grid):
    rows, cols = len(grid), len(grid[0])
    shapes = set()
    def dfs(i, j, direction):
        if i < 0 or i >= rows or j < 0 or j >= cols or grid[i][j] == 0:
            return ''
        grid[i][j] = 0
        return (direction + dfs(i+1, j, 'D') + dfs(i-1, j, 'U') + dfs(i, j+1, 'R') + dfs(i, j-1, 'L') + '0')
    for i in range(rows):
        for j in range(cols):
            if grid[i][j] == 1:
                shapes.add(dfs(i, j, 'O'))
    return len(shapes)

def removeAnagrams(words):
    result = [words[0]]
    for i in range(1, len(words)):
        if sorted(words[i]) != sorted(words[i-1]):
            result.append(words[i])
    return result

def maxLevelSum(root):
    from collections import deque
    if not root:
        return 0
    queue = deque([root])
    max_sum = float('-inf')
    level = max_level = 1
    while queue:
        level_sum = sum(node.val for node in queue)
        if level_sum > max_sum:
            max_sum = level_sum
            max_level = level
        for _ in range(len(queue)):
            node = queue.popleft()
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
        level += 1
    return max_level

def sumEvenGrandparent(root):
    def dfs(node, parent, grandparent):
        if not node:
            return 0
        total = 0
        if grandparent and grandparent % 2 == 0:
            total += node.val
        total += dfs(node.left, node.val, parent)
        total += dfs(node.right, node.val, parent)
        return total
    return dfs(root, None, None)

def deepestLeavesSum(root):
    from collections import deque
    queue = deque([root])
    while queue:
        level_sum = 0
        for _ in range(len(queue)):
            node = queue.popleft()
            level_sum += node.val
            if node.left:
                queue.append(node.left)
            if node.right:
                queue.append(node.right)
    return level_sum

def sumRootToLeaf(root):
    def dfs(node, current):
        if not node:
            return 0
        current = current * 2 + node.val
        if not node.left and not node.right:
            return current
        return dfs(node.left, current) + dfs(node.right, current)
    return dfs(root, 0)

def findBottomLeftValue(root):
    from collections import deque
    queue = deque([root])
    node = None
    while queue:
        node = queue.popleft()
        if node.right:
            queue.append(node.right)
        if node.left:
            queue.append(node.left)
    return node.val

def maxAncestorDiff(root):
    def dfs(node, curr_min, curr_max):
        if not node:
            return curr_max - curr_min
        curr_min = min(curr_min, node.val)
        curr_max = max(curr_max, node.val)
        left = dfs(node.left, curr_min, curr_max)
        right = dfs(node.right, curr_min, curr_max)
        return max(left, right)
    return dfs(root, root.val, root.val)

def goodNodes(root):
    def dfs(node, max_so_far):
        if not node:
            return 0
        total = 1 if node.val >= max_so_far else 0
        max_so_far = max(max_so_far, node.val)
        total += dfs(node.left, max_so_far)
        total += dfs(node.right, max_so_far)
        return total
    return dfs(root, root.val)

def minFlips(a, b, c):
    flips = 0
    for i in range(32):
        c_bit = (c >> i) & 1
        a_bit = (a >> i) & 1
        b_bit = (b >> i) & 1
        if c_bit == 0:
            flips += a_bit + b_bit
        else:
            if a_bit == 0 and b_bit == 0:
                flips += 1
    return flips

def findMaximumXOR(nums):
    max_xor = mask = 0
    for i in range(31, -1, -1):
        mask |= (1 << i)
        prefixes = {num & mask for num in nums}
        candidate = max_xor | (1 << i)
        for prefix in prefixes:
            if candidate ^ prefix in prefixes:
                max_xor = candidate
                break
    return max_xor

def eraseOverlapIntervals(intervals):
