def maxProfit(prices):
    if len(prices) < 2:
        return 0
    sold, held, rest = float('-inf'), float('-inf'), 0
    for price in prices:
        prev_sold = sold
        sold = held + price
        held = max(held, rest - price)
        rest = max(rest, prev_sold)
    return max(sold, rest)

def distanceK(root, target, k):
    from collections import defaultdict, deque
    graph = defaultdict(list)
    def build_graph(node, parent):
        if not node:
            return
        if parent:
            graph[node].append(parent)
            graph[parent].append(node)
        build_graph(node.left, node)
        build_graph(node.right, node)
    build_graph(root, None)
    queue = deque([(target, 0)])
    visited = {target}
    result = []
    while queue:
        node, dist = queue.popleft()
        if dist == k:
            result.append(node.val)
        elif dist < k:
            for neighbor in graph[node]:
                if neighbor not in visited:
                    visited.add(neighbor)
                    queue.append((neighbor, dist + 1))
    return result

def shortestDistance(grid):
    m, n = len(grid), len(grid[0])
    dist = [[0]*n for _ in range(m)]
    reach = [[0]*n for _ in range(m)]
    buildings = sum(grid[i][j] == 1 for i in range(m) for j in range(n))
    for i in range(m):
        for j in range(n):
            if grid[i][j] == 1:
                if not bfs(grid, dist, reach, i, j, buildings):
                    return -1
    min_dist = float('inf')
    for i in range(m):
        for j in range(n):
            if grid[i][j] == 0 and reach[i][j] == buildings:
                min_dist = min(min_dist, dist[i][j])
    return min_dist if min_dist != float('inf') else -1

def minKnightMoves(x, y):
    from collections import deque
    x, y = abs(x), abs(y)
    queue = deque([(0, 0, 0)])
    visited = {(0, 0)}
    directions = [(1,2),(2,1),(2,-1),(1,-2),(-1,-2),(-2,-1),(-2,1),(-1,2)]
    while queue:
        i, j, moves = queue.popleft()
        if i == x and j == y:
            return moves
        for di, dj in directions:
            ni, nj = i + di, j + dj
            if (ni, nj) not in visited and -2 <= ni <= x + 2 and -2 <= nj <= y + 2:
                visited.add((ni, nj))
                queue.append((ni, nj, moves + 1))

