def calcEquation(equations, values, queries):
    parent = {}
    weight = {}
    def find(x):
        if parent[x] != x:
            orig = parent[x]
            parent[x] = find(parent[x])
            weight[x] *= weight[orig]
        return parent[x]
    def union(x, y, val):
        root_x, root_y = find(x), find(y)
        if root_x != root_y:
            parent[root_x] = root_y
            weight[root_x] = val * weight[y] / weight[x]
    for (a, b), val in zip(equations, values):
        if a not in parent:
            parent[a] = a
            weight[a] = 1.0
        if b not in parent:
            parent[b] = b
            weight[b] = 1.0
        union(a, b, val)
    result = []
    for a, b in queries:
        if a in parent and b in parent and find(a) == find(b):
            result.append(weight[a] / weight[b])
        else:
            result.append(-1.0)
    return result

def medianSlidingWindow(nums, k):
    import heapq
    from collections import defaultdict
    lo, hi = [], []
    to_remove = defaultdict(int)
    def balance():
        while lo and to_remove[-lo[0]] > 0:
            to_remove[-lo[0]] -= 1
            heapq.heappop(lo)
        while hi and to_remove[hi[0]] > 0:
            to_remove[hi[0]] -= 1
            heapq.heappop(hi)
    for i in range(k):
        heapq.heappush(lo, -nums[i])
        heapq.heappush(hi, -heapq.heappop(lo))
        if len(hi) > len(lo):
            heapq.heappush(lo, -heapq.heappop(hi))
    get_median = lambda: -lo[0] if k % 2 else (-lo[0] + hi[0]) / 2
    result = [get_median()]
    for i in range(k, len(nums)):
        if nums[i-k] <= -lo[0]:
            to_remove[nums[i-k]] += 1
        else:
            to_remove[nums[i-k]] += 1
        heapq.heappush(lo, -nums[i])
        heapq.heappush(hi, -heapq.heappop(lo))
        if len(hi) > len(lo):
            heapq.heappush(lo, -heapq.heappop(hi))
        balance()
        result.append(get_median())
    return result

class SummaryRanges:
    def __init__(self):
        self.intervals = []
        import bisect
        self.bisect = bisect

    def addNum(self, val):
        i = self.bisect.bisect_left(self.intervals, [val, val])
        left = right = val
        if i > 0:
            if self.intervals[i-1][1] >= val - 1:
                left = self.intervals[i-1][0]
                right = max(right, self.intervals[i-1][1])
                self.intervals.pop(i-1)
                i -= 1
        if i < len(self.intervals):
            if self.intervals[i][0] <= val + 1:
                right = max(right, self.intervals[i][1])
                self.intervals.pop(i)
        self.intervals.insert(i, [left, right])

    def getIntervals(self):
        return self.intervals

def longestIncreasingPath(matrix):
    if not matrix:
        return 0
    m, n = len(matrix), len(matrix[0])
    cache = {}
    directions = [(0,1),(0,-1),(1,0),(-1,0)]
    def dfs(i, j):
        if (i, j) not in cache:
            max_path = 0
            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and matrix[ni][nj] > matrix[i][j]:
                    max_path = max(max_path, dfs(ni, nj))
            cache[(i, j)] = 1 + max_path
        return cache[(i, j)]
    return max(dfs(i, j) for i in range(m) for j in range(n))

def maxCoins(nums):
    nums = [1] + [n for n in nums if n > 0] + [1]
    n = len(nums)
    dp = [[0] * n for _ in range(n)]
    for gap in range(2, n):
        for left in range(n - gap):
            right = left + gap
            for i in range(left + 1, right):
                dp[left][right] = max(dp[left][right], nums[left]*nums[i]*nums[right] + dp[left][i] + dp[i][right])
    return dp[0][-1]

def maxPoints(points):
    from collections import defaultdict
    from math import gcd
    if len(points) <= 2:
        return len(points)
    max_count = 0
    for i, (x1, y1) in enumerate(points):
        slope_count = defaultdict(int)
        for j, (x2, y2) in enumerate(points):
            if i != j:
                dx, dy = x2 - x1, y2 - y1
                g = gcd(dx, dy)
                slope_count[(dx//g, dy//g)] += 1
        max_count = max(max_count, max(slope_count.values(), default=0) + 1)
    return max_count

def deleteDuplicates(head):
    dummy = ListNode(0)
    dummy.next = head
    prev = dummy
    while head:
        if head.next and head.val == head.next.val:
            while head.next and head.val == head.next.val:
                head = head.next
            prev.next = head.next
        else:
            prev = prev.next
        head = head.next
    return dummy.next

def findDuplicates(nums):
    result = []
