        self.nums = self.original[:]
        return self.nums

    def shuffle(self):
        import random
        for i in range(len(self.nums) - 1, 0, -1):
            j = random.randint(0, i)
            self.nums[i], self.nums[j] = self.nums[j], self.nums[i]
        return self.nums

def nthUglyNumber(n):
    ugly = [1]
    i2 = i3 = i5 = 0
    while len(ugly) < n:
        next2, next3, next5 = ugly[i2]*2, ugly[i3]*3, ugly[i5]*5
        next_ugly = min(next2, next3, next5)
        ugly.append(next_ugly)
        if next_ugly == next2:
            i2 += 1
        if next_ugly == next3:
            i3 += 1
        if next_ugly == next5:
            i5 += 1
    return ugly[-1]

def nthSuperUglyNumber(n, primes):
    ugly = [1]
    pointers = [0] * len(primes)
    while len(ugly) < n:
        candidates = [ugly[pointers[i]] * primes[i] for i in range(len(primes))]
        min_val = min(candidates)
        ugly.append(min_val)
        for i in range(len(primes)):
            if candidates[i] == min_val:
                pointers[i] += 1
    return ugly[-1]

def canCross(stones):
    stone_set = set(stones)
    memo = {}
    def dfs(pos, k):
        if pos == stones[-1]:
            return True
        if (pos, k) in memo:
            return memo[(pos, k)]
        for jump in [k-1, k, k+1]:
            if jump > 0 and pos + jump in stone_set:
                if dfs(pos + jump, jump):
                    memo[(pos, k)] = True
                    return True
        memo[(pos, k)] = False
        return False
    return dfs(0, 0)

def minInsertions(s):
    n = len(s)
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    for i in range(n):
        for j in range(n):
            if s[i] == s[n-1-j]:
                dp[i+1][j+1] = dp[i][j] + 1
            else:
                dp[i+1][j+1] = max(dp[i][j+1], dp[i+1][j])
    return n - dp[n][n]

class StockSpanner:
