def findKthBit(n, k):
    if n == 1:
        return '0'
    length = (1 << n) - 1
    mid = length // 2 + 1
    if k == mid:
        return '1'
    elif k < mid:
        return findKthBit(n - 1, k)
    else:
        return '1' if findKthBit(n - 1, length - k + 1) == '0' else '0'

def wordSubsets(A, B):
    from collections import Counter
    b_max = Counter()
    for b in B:
        b_count = Counter(b)
        for c in b_count:
            b_max[c] = max(b_max[c], b_count[c])
    result = []
    for a in A:
        a_count = Counter(a)
        if all(a_count[c] >= b_max[c] for c in b_max):
            result.append(a)
    return result

