def champagneTower(poured, query_row, query_glass):
    tower = [[0.0] * k for k in range(1, 102)]
    tower[0][0] = poured
    for r in range(query_row + 1):
        for c in range(r + 1):
            q = (tower[r][c] - 1.0) / 2.0
            if q > 0:
                tower[r+1][c] += q
                tower[r+1][c+1] += q
    return min(1.0, tower[query_row][query_glass])

def longestStrChain(words):
    words.sort(key=len)
    dp = {}
    max_chain = 1
    for word in words:
        dp[word] = 1
        for i in range(len(word)):
            prev = word[:i] + word[i+1:]
            if prev in dp:
                dp[word] = max(dp[word], dp[prev] + 1)
        max_chain = max(max_chain, dp[word])
    return max_chain

def singleNonDuplicate(nums):
    left, right = 0, len(nums) - 1
    while left < right:
        mid = (left + right) // 2
        if mid % 2 == 1:
            mid -= 1
        if nums[mid] == nums[mid+1]:
            left = mid + 2
        else:
            right = mid
    return nums[left]

def preimageSizeFZF(K):
    def trailingZeroes(n):
        count = 0
        while n:
            n //= 5
            count += n
        return count
    lo, hi = 0, 5 * (K + 1)
    while lo < hi:
        mid = (lo + hi) // 2
        if trailingZeroes(mid) < K:
            lo = mid + 1
        else:
            hi = mid
    left = lo
    lo, hi = 0, 5 * (K + 1)
    while lo < hi:
        mid = (lo + hi) // 2
        if trailingZeroes(mid) <= K:
            lo = mid + 1
        else:
            hi = mid
    right = lo
    return right - left

def minAreaRect(points):
    from collections import defaultdict
    columns = defaultdict(set)
    for x, y in points:
        columns[x].add(y)
    min_area = float('inf')
    x_coords = list(columns.keys())
    for i in range(len(x_coords)):
        for j in range(i + 1, len(x_coords)):
            x1, x2 = x_coords[i], x_coords[j]
            common_y = sorted(columns[x1] & columns[x2])
            for k in range(len(common_y) - 1):
                min_area = min(min_area, abs(x1 - x2) * (common_y[k+1] - common_y[k]))
    return min_area if min_area != float('inf') else 0

def numSubmatrixSumTarget(matrix, target):
    m, n = len(matrix), len(matrix[0])
    for i in range(m):
        for j in range(1, n):
            matrix[i][j] += matrix[i][j-1]
    count = 0
    for col1 in range(n):
        for col2 in range(col1, n):
            prefix_sum = {0: 1}
            curr_sum = 0
            for row in range(m):
                curr_sum += matrix[row][col2] - (matrix[row][col1-1] if col1 > 0 else 0)
                count += prefix_sum.get(curr_sum - target, 0)
                prefix_sum[curr_sum] = prefix_sum.get(curr_sum, 0) + 1
    return count

def maximalSquare(matrix):
    if not matrix:
        return 0
    m, n = len(matrix), len(matrix[0])
    dp = [0] * (n + 1)
    max_side = prev = 0
    for i in range(m):
        for j in range(1, n + 1):
            temp = dp[j]
            if matrix[i][j-1] == '1':
                dp[j] = min(dp[j], dp[j-1], prev) + 1
                max_side = max(max_side, dp[j])
            else:
                dp[j] = 0
            prev = temp
    return max_side * max_side

def solve(board):
    if not board:
        return
    m, n = len(board), len(board[0])
    def dfs(i, j):
        if i<0 or i>=m or j<0 or j>=n or board[i][j] != 'O':
            return
        board[i][j] = 'T'
        dfs(i+1, j)
        dfs(i-1, j)
        dfs(i, j+1)
        dfs(i, j-1)
    for i in range(m):
        dfs(i, 0)
        dfs(i, n-1)
    for j in range(n):
        dfs(0, j)
        dfs(m-1, j)
    for i in range(m):
        for j in range(n):
            if board[i][j] == 'O':
                board[i][j] = 'X'
            elif board[i][j] == 'T':
                board[i][j] = 'O'

def cherryPickup(grid):
    n = len(grid)
    dp = [[[float('-inf')] * n for _ in range(n)] for _ in range(n)]
    dp[0][0][0] = grid[0][0]
    for t in range(1, 2*n - 1):
        for i in range(min(n, t+1)-1, max(-1, t-n), -1):
            for p in range(min(n, t+1)-1, max(-1, t-n), -1):
                j, q = t - i, t - p
                if grid[i][j] == -1 or grid[p][q] == -1:
                    dp[i][p][t%2] = float('-inf')
                    continue
                if i > 0 and p > 0:
                    dp[i][p][t%2] = max(dp[i][p][t%2], dp[i-1][p-1][(t-1)%2])
                if i > 0 and q > 0:
                    dp[i][p][t%2] = max(dp[i][p][t%2], dp[i-1][p][(t-1)%2])
                if j > 0 and p > 0:
                    dp[i][p][t%2] = max(dp[i][p][t%2], dp[i][p-1][(t-1)%2])
                if j > 0 and q > 0:
                    dp[i][p][t%2] = max(dp[i][p][t%2], dp[i][p][(t-1)%2])
                if dp[i][p][t%2] >= 0:
                    dp[i][p][t%2] += grid[i][j] + (grid[p][q] if i != p else 0)
    return max(0, dp[n-1][n-1][(2*n-2)%2])

def accountsMerge(accounts):
    from collections import defaultdict
    parent = {}
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    def union(x, y):
        parent[find(x)] = find(y)
    email_to_name = {}
    for account in accounts:
        name = account[0]
        for email in account[1:]:
            if email not in parent:
                parent[email] = email
            email_to_name[email] = name
            union(email, account[1])
    groups = defaultdict(list)
    for email in parent:
        groups[find(email)].append(email)
    return [[email_to_name[root]] + sorted(emails) for root, emails in groups.items()]

def mergeStones(stones, K):
    n = len(stones)
    if (n - 1) % (K - 1) != 0:
        return -1
    prefix = [0]
    for stone in stones:
        prefix.append(prefix[-1] + stone)
    dp = [[0] * n for _ in range(n)]
    for length in range(K, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            dp[i][j] = float('inf')
            for mid in range(i, j, K - 1):
                dp[i][j] = min(dp[i][j], dp[i][mid] + dp[mid+1][j])
            if (j - i) % (K - 1) == 0:
                dp[i][j] += prefix[j+1] - prefix[i]
    return dp[0][-1]

def palindromePairs(words):
    word_map = {word: i for i, word in enumerate(words)}
    result = []
    for i, word in enumerate(words):
        for j in range(len(word) + 1):
            prefix = word[:j]
            suffix = word[j:]
            if prefix == prefix[::-1]:
                rev_suffix = suffix[::-1]
                if rev_suffix != word and rev_suffix in word_map:
                    result.append([word_map[rev_suffix], i])
            if j != len(word) and suffix == suffix[::-1]:
                rev_prefix = prefix[::-1]
                if rev_prefix != word and rev_prefix in word_map:
                    result.append([i, word_map[rev_prefix]])
    return result

def slidingPuzzle(board):
    from collections import deque
    target = (1,2,3,4,5,0)
    start = tuple(board[0] + board[1])
    if start == target:
        return 0
    moves = {0: [1,3], 1: [0,2,4], 2: [1,5], 3: [0,4], 4: [1,3,5], 5: [2,4]}
    queue = deque([(start, start.index(0), 0)])
    visited = {start}
    while queue:
        state, zero, steps = queue.popleft()
        for nxt in moves[zero]:
            new_state = list(state)
            new_state[zero], new_state[nxt] = new_state[nxt], new_state[zero]
            new_state = tuple(new_state)
            if new_state == target:
                return steps + 1
            if new_state not in visited:
                visited.add(new_state)
                queue.append((new_state, nxt, steps + 1))
    return -1

def crackSafe(n, k):
    if n == 1:
        return ''.join(str(i) for i in range(k))
    from collections import defaultdict
    edges = defaultdict(lambda: k - 1)
    result = ['0'] * (n - 1)
    node = ''.join(result)
    while edges[node] >= 0:
        result.append(str(edges[node]))
        next_node = node[1:] + str(edges[node])
        edges[node] -= 1
        node = next_node
    return ''.join(result)

def smallestSufficientTeam(req_skills, people):
    skill_idx = {skill: i for i, skill in enumerate(req_skills)}
    n = len(req_skills)
    people_skills = []
    for person in people:
        mask = 0
        for skill in person:
            mask |= (1 << skill_idx[skill])
        people_skills.append(mask)
    dp = {0: []}
    for i, mask in enumerate(people_skills):
        if mask == 0:
            continue
        for state in list(dp.keys()):
            new_state = state | mask
            if new_state not in dp or len(dp[state]) + 1 < len(dp[new_state]):
                dp[new_state] = dp[state] + [i]
    return dp[(1 << n) - 1]

def containsNearbyAlmostDuplicate(nums, k, t):
    if t < 0 or k <= 0:
        return False
    buckets = {}
    width = t + 1
    for i, num in enumerate(nums):
        bucket = num // width
        if bucket in buckets:
            return True
        if bucket - 1 in buckets and abs(num - buckets[bucket - 1]) < width:
            return True
        if bucket + 1 in buckets and abs(num - buckets[bucket + 1]) < width:
            return True
        buckets[bucket] = num
        if i >= k:
            del buckets[nums[i - k] // width]
    return False

def uniqueLetterString(s):
    index = {c: [-1, -1] for c in string.ascii_uppercase}
    result = 0
    for i, c in enumerate(s):
        second_last, last = index[c]
        result += (i - last) * (last - second_last)
        index[c] = [last, i]
    for c in index:
        second_last, last = index[c]
        result += (len(s) - last) * (last - second_last)
    return result

class RangeModule:
    def __init__(self):
        import bisect
        self.intervals = []

    def addRange(self, left, right):
        import bisect
        i = bisect.bisect_left(self.intervals, [left, left])
        if i > 0 and self.intervals[i-1][1] >= left:
            i -= 1
        while i < len(self.intervals) and self.intervals[i][0] <= right:
            left = min(left, self.intervals[i][0])
            right = max(right, self.intervals[i][1])
            self.intervals.pop(i)
        self.intervals.insert(i, [left, right])

    def queryRange(self, left, right):
        import bisect
        i = bisect.bisect_right(self.intervals, [left, float('inf')])
        return i > 0 and self.intervals[i-1][1] >= right

    def removeRange(self, left, right):
        import bisect
        i = bisect.bisect_left(self.intervals, [left, left])
        if i > 0 and self.intervals[i-1][1] >= left:
            i -= 1
        new_intervals = []
        for start, end in self.intervals[i:]:
            if start >= right:
                new_intervals.append([start, end])
            else:
                if start < left:
                    new_intervals.append([start, left])
                if end > right:
                    new_intervals.append([right, end])
        self.intervals[i:] = new_intervals

def shortestPathLength(graph):
    from collections import deque
    n = len(graph)
    if n == 1:
        return 0
    target = (1 << n) - 1
    queue = deque([(i, 1 << i, 0) for i in range(n)])
    visited = {(i, 1 << i) for i in range(n)}
    while queue:
        node, mask, dist = queue.popleft()
        for neighbor in graph[node]:
            new_mask = mask | (1 << neighbor)
            if new_mask == target:
                return dist + 1
            if (neighbor, new_mask) not in visited:
                visited.add((neighbor, new_mask))
                queue.append((neighbor, new_mask, dist + 1))

def findNumberOfLIS(nums):
    n = len(nums)
    if n == 0:
        return 0
    lengths = [1] * n
    counts = [1] * n
    for i in range(n):
        for j in range(i):
            if nums[j] < nums[i]:
                if lengths[j] + 1 > lengths[i]:
                    lengths[i] = lengths[j] + 1
                    counts[i] = counts[j]
                elif lengths[j] + 1 == lengths[i]:
                    counts[i] += counts[j]
    max_len = max(lengths)
    return sum(counts[i] for i in range(n) if lengths[i] == max_len)

def maxEnvelopes(envelopes):
    import bisect
    envelopes.sort(key=lambda x: (x[0], -x[1]))
    heights = [h for _, h in envelopes]
    tails = []
    for h in heights:
        i = bisect.bisect_left(tails, h)
        if i == len(tails):
            tails.append(h)
        else:
            tails[i] = h
    return len(tails)

def maxNumber(nums1, nums2, k):
    def max_sequence(nums, k):
        stack = []
        to_pop = len(nums) - k
        for num in nums:
            while stack and to_pop > 0 and stack[-1] < num:
                stack.pop()
                to_pop -= 1
            stack.append(num)
        return stack[:k]
    def merge(seq1, seq2):
        result = []
        while seq1 or seq2:
            if seq1 > seq2:
                result.append(seq1.pop(0))
            else:
                result.append(seq2.pop(0))
        return result
    result = []
    for i in range(max(0, k - len(nums2)), min(k, len(nums1)) + 1):
        seq1 = max_sequence(nums1, i)
        seq2 = max_sequence(nums2, k - i)
        result = max(result, merge(seq1, seq2))
    return result

def ipToCIDR(ip, n):
    def ip_to_int(ip):
        parts = list(map(int, ip.split('.')))
        return (parts[0] << 24) + (parts[1] << 16) + (parts[2] << 8) + parts[3]
    def int_to_ip(num):
        return f'{num>>24}.{(num>>16)&255}.{(num>>8)&255}.{num&255}'
    result = []
    curr = ip_to_int(ip)
    while n > 0:
        if curr == 0:
            step = 1 << (32 - 1)
            while step > n:
                step //= 2
        else:
            step = curr & -curr
            while step > n:
                step //= 2
        result.append(f'{int_to_ip(curr)}/{32 - (step.bit_length() - 1)}')
        curr += step
        n -= step
    return result

class MedianFinder:
    def __init__(self):
        import heapq
        self.lo = []  # max-heap (inverted)
        self.hi = []  # min-heap

    def addNum(self, num):
        heapq.heappush(self.lo, -num)
        heapq.heappush(self.hi, -heapq.heappop(self.lo))
        if len(self.hi) > len(self.lo):
            heapq.heappush(self.lo, -heapq.heappop(self.hi))

    def findMedian(self):
        if len(self.lo) > len(self.hi):
            return -self.lo[0]
        return (-self.lo[0] + self.hi[0]) / 2

def isRectangleCover(rectangles):
    corners = set()
    area = 0
    x1, y1, x2, y2 = float('inf'), float('inf'), float('-inf'), float('-inf')
    for x_min, y_min, x_max, y_max in rectangles:
        x1 = min(x1, x_min)
        y1 = min(y1, y_min)
        x2 = max(x2, x_max)
        y2 = max(y2, y_max)
        area += (x_max - x_min) * (y_max - y_min)
        for corner in [(x_min, y_min), (x_min, y_max), (x_max, y_min), (x_max, y_max)]:
            if corner in corners:
                corners.remove(corner)
            else:
                corners.add(corner)
    if area != (x2 - x1) * (y2 - y1):
        return False
    return corners == {(x1, y1), (x1, y2), (x2, y1), (x2, y2)}

def cutOffTree(forest):
    m, n = len(forest), len(forest[0])
    trees = [(forest[i][j], i, j) for i in range(m) for j in range(n) if forest[i][j] > 1]
    trees.sort()
    from collections import deque
    def bfs(si, sj, ti, tj):
        queue = deque([(si, sj, 0)])
        visited = {(si, sj)}
        while queue:
            i, j, steps = queue.popleft()
            if i == ti and j == tj:
                return steps
            for di, dj in [(0,1), (0,-1), (1,0), (-1,0)]:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n and (ni, nj) not in visited and forest[ni][nj] > 0:
                    visited.add((ni, nj))
                    queue.append((ni, nj, steps + 1))
        return -1
    total = 0
    si = sj = 0
    for _, ti, tj in trees:
        steps = bfs(si, sj, ti, tj)
        if steps == -1:
            return -1
        total += steps
        si, sj = ti, tj
    return total

def strangePrinter(s):
    n = len(s)
    if n == 0:
        return 0
    dp = [[0] * n for _ in range(n)]
    for i in range(n-1, -1, -1):
        dp[i][i] = 1
        for j in range(i+1, n):
            dp[i][j] = dp[i][j-1] + 1
            for k in range(i, j):
                if s[k] == s[j]:
                    dp[i][j] = min(dp[i][j], dp[i][k] + dp[k+1][j-1])
    return dp[0][-1]

def employeeFreeTime(schedule):
    intervals = []
    for emp in schedule:
        intervals.extend(emp)
    intervals.sort(key=lambda x: x[0])
    merged = []
    for start, end in intervals:
        if not merged or merged[-1][1] < start:
            merged.append([start, end])
        else:
            merged[-1][1] = max(merged[-1][1], end)
    result = []
    for i in range(1, len(merged)):
        result.append([merged[i-1][1], merged[i][0]])
    return result

def minimumMoves(arr):
    n = len(arr)
    dp = [[0] * n for _ in range(n)]
    for i in range(n):
        dp[i][i] = 1
    for length in range(2, n+1):
        for i in range(n - length + 1):
            j = i + length - 1
            dp[i][j] = 1 + dp[i+1][j] if i+1 <= j else 1
            if arr[i] == arr[i+1]:
                dp[i][j] = min(dp[i][j], 1 + (dp[i+2][j] if i+2 <= j else 0))
            for k in range(i+2, j+1):
                if arr[i] == arr[k]:
                    dp[i][j] = min(dp[i][j], dp[i+1][k-1] + (dp[k+1][j] if k+1 <= j else 0))
    return dp[0][-1]

def findShortestWay(maze, ball, hole):
    import heapq
    m, n = len(maze), len(maze[0])
    directions = [(-1,0,'u'), (1,0,'d'), (0,-1,'l'), (0,1,'r')]
    start = (ball[0], ball[1])
    heap = [(0, '', start[0], start[1])]
    visited = {start: (0, '')}
    while heap:
        dist, path, i, j = heapq.heappop(heap)
        if [i, j] == hole:
            return path
        if (i, j) in visited and visited[(i, j)] < (dist, path):
            continue
        for di, dj, d in directions:
            ni, nj, steps = i, j, 0
            while 0 <= ni+di < m and 0 <= nj+dj < n and maze[ni+di][nj+dj] == 0:
                ni += di
                nj += dj
                steps += 1
                if [ni, nj] == hole:
                    break
            new_state = (ni, nj)
            new_dist = dist + steps
            new_path = path + d
            if new_state not in visited or visited[new_state] > (new_dist, new_path):
                visited[new_state] = (new_dist, new_path)
                heapq.heappush(heap, (new_dist, new_path, ni, nj))
    return 'impossible'

def numDistinct(s, t):
    m, n = len(s), len(t)
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, m + 1):
        for j in range(n, 0, -1):
            if s[i-1] == t[j-1]:
                dp[j] += dp[j-1]
    return dp[-1]

def shortestDistanceColor(colors, queries):
    n = len(colors)
    left = [[-1]*3 for _ in range(n)]
    right = [[-1]*3 for _ in range(n)]
    for c in range(3):
        pos = -1
        for i in range(n):
            if colors[i] == c + 1:
                pos = i
            left[i][c] = pos
        pos = -1
        for i in range(n-1, -1, -1):
            if colors[i] == c + 1:
                pos = i
            right[i][c] = pos
    result = []
    for idx, c in queries:
        l = left[idx][c-1]
        r = right[idx][c-1]
        if l == -1 and r == -1:
            result.append(-1)
        elif l == -1:
            result.append(r - idx)
        elif r == -1:
            result.append(idx - l)
        else:
            result.append(min(idx - l, r - idx))
    return result

def largestComponentSize(A):
    from collections import defaultdict
    import math
    parent = {}
    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]
    def union(x, y):
        parent[find(x)] = find(y)
    for num in A:
        for factor in range(2, int(math.sqrt(num)) + 1):
            if num % factor == 0:
                if factor not in parent:
                    parent[factor] = factor
                if num not in parent:
                    parent[num] = num
                union(num, factor)
                other = num // factor
                if other > 1:
                    if other not in parent:
                        parent[other] = other
                    union(num, other)
    count = defaultdict(int)
    for num in A:
        if num in parent:
            count[find(num)] += 1
    return max(count.values()) if count else 1

def gridIllumination(N, lamps, queries):
    rows, cols, diags, anti_diags = {}, {}, {}, {}
    lamp_set = set()
    for r, c in lamps:
        if (r, c) in lamp_set:
            continue
        lamp_set.add((r, c))
        rows[r] = rows.get(r, 0) + 1
        cols[c] = cols.get(c, 0) + 1
        diags[r-c] = diags.get(r-c, 0) + 1
        anti_diags[r+c] = anti_diags.get(r+c, 0) + 1
    result = []
    for r, c in queries:
        if rows.get(r, 0) > 0 or cols.get(c, 0) > 0 or diags.get(r-c, 0) > 0 or anti_diags.get(r+c, 0) > 0:
            result.append(1)
        else:
            result.append(0)
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                nr, nc = r + dr, c + dc
                if (nr, nc) in lamp_set:
                    lamp_set.remove((nr, nc))
                    rows[nr] -= 1
                    cols[nc] -= 1
                    diags[nr-nc] -= 1
                    anti_diags[nr+nc] -= 1
    return result

def movesToChessboard(board):
    n = len(board)
    if n == 0:
        return 0
    for i in range(n):
        for j in range(n):
            if board[0][0] ^ board[0][j] ^ board[i][0] ^ board[i][j]:
                return -1
    row_sum = sum(board[0])
    col_sum = sum(board[i][0] for i in range(n))
    if row_sum != n//2 and row_sum != (n+1)//2:
        return -1
    if col_sum != n//2 and col_sum != (n+1)//2:
        return -1
    row_diff = sum(board[0][i] != (i % 2) for i in range(n))
    col_diff = sum(board[i][0] != (i % 2) for i in range(n))
    if n % 2:
        if row_diff % 2:
            row_diff = n - row_diff
        if col_diff % 2:
            col_diff = n - col_diff
    else:
        row_diff = min(row_diff, n - row_diff)
        col_diff = min(col_diff, n - col_diff)
    return (row_diff + col_diff) // 2

def constrainedSubsetSum(nums, k):
    from collections import deque
    dp = nums[:]
    dq = deque()
    for i in range(len(nums)):
        if dq and dq[0] < i - k:
            dq.popleft()
        if dq:
            dp[i] = max(dp[i], nums[i] + dp[dq[0]])
        while dq and dp[dq[-1]] <= dp[i]:
            dq.pop()
        if dp[i] > 0:
            dq.append(i)
    return max(dp)

def wordSquares(words):
    from collections import defaultdict
    prefix_map = defaultdict(list)
    for word in words:
        for i in range(len(word)):
            prefix_map[word[:i+1]].append(word)
    result = []
    def backtrack(square):
        if len(square) == len(words[0]):
            result.append(square[:])
            return
        idx = len(square)
        prefix = ''.join(word[idx] for word in square)
        for word in prefix_map[prefix]:
            square.append(word)
            backtrack(square)
            square.pop()
    for word in words:
        backtrack([word])
    return result

def racecar(target):
    from collections import deque
    queue = deque([(0, 1, 0)])
    visited = {(0, 1)}
    while queue:
        pos, speed, steps = queue.popleft()
        if pos == target:
            return steps
        # Accelerate
        new_pos = pos + speed
        new_speed = speed * 2
        if (new_pos, new_speed) not in visited and new_pos > 0 and new_pos < 2 * target:
            visited.add((new_pos, new_speed))
            queue.append((new_pos, new_speed, steps + 1))
        # Reverse
        new_speed = -1 if speed > 0 else 1
        if (pos, new_speed) not in visited:
            visited.add((pos, new_speed))
            queue.append((pos, new_speed, steps + 1))

def sumOfDistancesInTree(N, edges):
    from collections import defaultdict
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        graph[v].append(u)
    count = [1] * N
    result = [0] * N
    def dfs1(node, parent):
        for child in graph[node]:
            if child != parent:
                dfs1(child, node)
                count[node] += count[child]
                result[node] += result[child] + count[child]
    def dfs2(node, parent):
        for child in graph[node]:
            if child != parent:
                result[child] = result[node] - count[child] + N - count[child]
                dfs2(child, node)
    dfs1(0, -1)
    dfs2(0, -1)
    return result

def isValidPalindrome(s, k):
    n = len(s)
    dp = [[0] * n for _ in range(n)]
    for i in range(n-1, -1, -1):
        dp[i][i] = 1
        for j in range(i+1, n):
            if s[i] == s[j]:
                dp[i][j] = dp[i+1][j-1] + 2
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j-1])
    return n - dp[0][-1] <= k

class Excel:
    def __init__(self, H, W):
        self.cells = {}
        self.H = H

    def set(self, r, c, v):
        self.cells[(r, c)] = v

    def get(self, r, c):
        return self.cells.get((r, c), 0)

    def sum(self, r, c, strs):
        total = 0
        for s in strs:
            if ':' in s:
                start, end = s.split(':')
                for row in range(int(start[1:]), int(end[1:]) + 1):
                    for col in range(ord(start[0]), ord(end[0]) + 1):
                        total += self.get(row, chr(col))
            else:
                total += self.get(int(s[1:]), s[0])
        self.set(r, c, total)
        return total

def canConvert(str1, str2):
    if str1 == str2:
        return True
    mapping = {}
    for c1, c2 in zip(str1, str2):
        if mapping.get(c1, c2) != c2:
