        mapping[c1] = c2
    return len(set(str2)) < 26

def minCameraCover(root):
    cameras = 0
    def dfs(node):
        nonlocal cameras
        if not node:
            return 2
        left = dfs(node.left)
        right = dfs(node.right)
        if left == 0 or right == 0:
            cameras += 1
            return 1
        if left == 1 or right == 1:
            return 2
        return 0
    if dfs(root) == 0:
        cameras += 1
    return cameras

def longestDupSubstring(s):
    n = len(s)
    def search(length):
        MOD = 2**63 - 1
        BASE = 26
        hash_val = 0
        for i in range(length):
            hash_val = (hash_val * BASE + ord(s[i]) - ord('a')) % MOD
        seen = {hash_val}
        base_l = pow(BASE, length, MOD)
        for i in range(1, n - length + 1):
            hash_val = (hash_val * BASE - (ord(s[i-1]) - ord('a')) * base_l + ord(s[i+length-1]) - ord('a')) % MOD
            if hash_val in seen:
                return i
            seen.add(hash_val)
        return -1
    left, right = 1, n
    result = ''
    while left <= right:
        mid = (left + right) // 2
        idx = search(mid)
        if idx != -1:
            result = s[idx:idx+mid]
            left = mid + 1
        else:
            right = mid - 1
    return result

def profitableSchemes(n, minProfit, group, profit):
    MOD = 10**9 + 7
    dp = [[0] * (n + 1) for _ in range(minProfit + 1)]
    dp[0][0] = 1
    for g, p in zip(group, profit):
        for i in range(minProfit, -1, -1):
            for j in range(n - g, -1, -1):
                new_profit = min(minProfit, i + p)
                dp[new_profit][j + g] = (dp[new_profit][j + g] + dp[i][j]) % MOD
    return sum(dp[minProfit]) % MOD

def isNStraightHand(hand, W):
    from collections import Counter
    if len(hand) % W != 0:
        return False
    count = Counter(hand)
    for card in sorted(count):
        if count[card] > 0:
            freq = count[card]
            for i in range(W):
                if count[card + i] < freq:
                    return False
                count[card + i] -= freq
    return True

def canReorderDoubled(arr):
    from collections import Counter
    count = Counter(arr)
    for x in sorted(count, key=abs):
        if count[x] > count[2 * x]:
            return False
        count[2 * x] -= count[x]
    return True

def integerReplacement(n):
    if n == 1:
        return 0
    if n % 2 == 0:
        return 1 + integerReplacement(n // 2)
    else:
        return 1 + min(integerReplacement(n + 1), integerReplacement(n - 1))

def minMutation(start, end, bank):
    from collections import deque
    if end not in bank:
        return -1
    bank = set(bank)
    queue = deque([(start, 0)])
    visited = {start}
    while queue:
        gene, mutations = queue.popleft()
        if gene == end:
            return mutations
        for i in range(len(gene)):
            for c in 'ACGT':
                if c != gene[i]:
                    new_gene = gene[:i] + c + gene[i+1:]
                    if new_gene in bank and new_gene not in visited:
                        visited.add(new_gene)
                        queue.append((new_gene, mutations + 1))
    return -1

def findRotateSteps(ring, key):
    from collections import defaultdict
    n = len(ring)
    pos = defaultdict(list)
    for i, c in enumerate(ring):
        pos[c].append(i)
    memo = {}
    def dp(i, j):
        if i == len(key):
            return 0
        if (i, j) in memo:
            return memo[(i, j)]
        min_steps = float('inf')
        for k in pos[key[i]]:
            diff = abs(j - k)
            steps = min(diff, n - diff)
            min_steps = min(min_steps, steps + dp(i + 1, k))
        memo[(i, j)] = min_steps + 1
        return memo[(i, j)]
    return dp(0, 0)

def evaluate(expression):
    def parse(tokens, scope):
        if tokens[0] in ('add', 'mult'):
            op = tokens[0]
            val1 = parse(tokens[1], scope)
            val2 = parse(tokens[2], scope)
            return val1 + val2 if op == 'add' else val1 * val2
        elif tokens[0] == 'let':
            new_scope = scope.copy()
            i = 1
            while i < len(tokens) - 1:
                if i + 1 == len(tokens) - 1:
                    return parse([tokens[i]], new_scope)
                new_scope[tokens[i]] = parse([tokens[i+1]], new_scope)
                i += 2
        else:
            token = tokens[0]
            if token in scope:
                return scope[token]
            return int(token)
    return parse([Tokenize(expression)], {})

def getSkyline(buildings):
    import heapq
    events = []
    for L, R, H in buildings:
        events.append((L, -H, R))
        events.append((R, 0, 0))
    events.sort()
    result = [[0, 0]]
    heap = [(0, float('inf'))]
    for pos, neg_h, R in events:
        if neg_h != 0:
            heapq.heappush(heap, (neg_h, R))
        while heap and heap[0][1] <= pos:
            heapq.heappop(heap)
        curr_height = -heap[0][0]
        if curr_height != result[-1][1]:
            result.append([pos, curr_height])
    return result[1:]

def isMatch(s, p):
    m, n = len(s), len(p)
    dp = [[False] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = True
    for j in range(2, n + 1):
        if p[j-1] == '*':
            dp[0][j] = dp[0][j-2]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if p[j-1] == '*':
                dp[i][j] = dp[i][j-2] or (dp[i-1][j] and (p[j-2] == '.' or s[i-1] == p[j-2]))
            else:
                dp[i][j] = dp[i-1][j-1] and (p[j-1] == '.' or s[i-1] == p[j-1])
    return dp[-1][-1]

def minTransfers(transactions):
    from collections import defaultdict
    balance = defaultdict(int)
    for u, v, amount in transactions:
        balance[u] -= amount
        balance[v] += amount
    debts = [b for b in balance.values() if b != 0]
    def dfs(start):
        while start < len(debts) and debts[start] == 0:
            start += 1
        if start == len(debts):
            return 0
        min_txns = float('inf')
        for i in range(start + 1, len(debts)):
            if debts[start] * debts[i] < 0:
                debts[i] += debts[start]
                min_txns = min(min_txns, 1 + dfs(start + 1))
                debts[i] -= debts[start]
        return min_txns
    return dfs(0)

def lengthLongestPath(input):
    max_len = 0
    path_len = {0: 0}
    for line in input.split('\n'):
        name = line.lstrip('\t')
        depth = len(line) - len(name)
        if '.' in name:
            max_len = max(max_len, path_len[depth] + len(name))
        else:
            path_len[depth + 1] = path_len[depth] + len(name) + 1
    return max_len

def findCelebrity(n):
    candidate = 0
    for i in range(1, n):
        if knows(candidate, i):
            candidate = i
    for i in range(n):
        if i != candidate and (knows(candidate, i) or not knows(i, candidate)):
            return -1
    return candidate

def kEmptySlots(flowers, k):
    n = len(flowers)
    days = [0] * n
    for day, pos in enumerate(flowers):
        days[pos-1] = day
    result = float('inf')
    left, right = 0, k + 1
    while right < n:
        valid = True
        for i in range(left + 1, right):
            if days[i] < days[left] or days[i] < days[right]:
                left = i
                right = i + k + 1
                valid = False
                break
        if valid:
            result = min(result, max(days[left], days[right]))
            left = right
            right = left + k + 1
    return result if result != float('inf') else -1

class SnapshotArray:
    def __init__(self, length):
        import bisect
        self.snap_id = 0
        self.data = [[[0, 0]] for _ in range(length)]

    def set(self, index, val):
        last = self.data[index][-1]
        if last[0] == self.snap_id:
            last[1] = val
        else:
            self.data[index].append([self.snap_id, val])

    def snap(self):
        self.snap_id += 1
        return self.snap_id - 1

    def get(self, index, snap_id):
        import bisect
        i = bisect.bisect_right(self.data[index], [snap_id, float('inf')])
        return self.data[index][i-1][1]

def getHint(secret, guess):
    bulls = cows = 0
    count = [0] * 10
    for s, g in zip(secret, guess):
        if s == g:
            bulls += 1
        else:
            if count[int(s)] < 0:
                cows += 1
            if count[int(g)] > 0:
                cows += 1
            count[int(s)] += 1
            count[int(g)] -= 1
    return f'{bulls}A{cows}B'

def wordsTyping(sentence, rows, cols):
    s = ' '.join(sentence) + ' '
    start = 0
    n = len(s)
    for _ in range(rows):
        start += cols
        if s[start % n] == ' ':
            start += 1
        else:
            while start > 0 and s[(start - 1) % n] != ' ':
                start -= 1
    return start // n

class MovingAverage:
    def __init__(self, size):
        from collections import deque
        self.size = size
        self.queue = deque()
        self.sum = 0

    def next(self, val):
        self.queue.append(val)
        self.sum += val
        if len(self.queue) > self.size:
            self.sum -= self.queue.popleft()
        return self.sum / len(self.queue)

def kthSmallestPath(destination, k):
    from math import comb
    row, col = destination
    result = []
    remaining_v = row
    remaining_h = col
    while remaining_h + remaining_v > 0:
        if remaining_h > 0:
            count = comb(remaining_h + remaining_v - 1, remaining_v)
            if k <= count:
                result.append('H')
                remaining_h -= 1
            else:
                result.append('V')
                k -= count
                remaining_v -= 1
        else:
            result.append('V')
            remaining_v -= 1
    return ''.join(result)

def mostCompetitive(nums, k):
    stack = []
    n = len(nums)
    for i, num in enumerate(nums):
        while stack and stack[-1] > num and len(stack) + n - i > k:
            stack.pop()
        if len(stack) < k:
            stack.append(num)
    return stack

def gardenNoAdj(N, paths):
    from collections import defaultdict
    graph = defaultdict(list)
    for u, v in paths:
        graph[u].append(v)
        graph[v].append(u)
    result = [0] * N
    for i in range(1, N + 1):
        used_colors = set()
        for neighbor in graph[i]:
            if result[neighbor - 1] != 0:
                used_colors.add(result[neighbor - 1])
        for color in range(1, 5):
            if color not in used_colors:
                result[i - 1] = color
                break
    return result

def isValid(s):
    stack = []
    for c in s:
        stack.append(c)
        if len(stack) >= 3 and stack[-3:] == ['a', 'b', 'c']:
            stack.pop()
            stack.pop()
            stack.pop()
    return not stack

def countTriplets(arr):
    n = len(arr)
    prefix_xor = [0] * (n + 1)
    for i in range(n):
        prefix_xor[i+1] = prefix_xor[i] ^ arr[i]
    count = 0
    for i in range(n):
        for k in range(i + 1, n):
            if prefix_xor[i] == prefix_xor[k+1]:
                count += k - i
    return count
